#include "epd2in66g.h"
#include <stdlib.h>
#include <string.h>
int EPD_epd2in66g_Init(EPD *epd){if(!epd)return EPD_ERROR;epd->width=152;epd->height=296;epd->rst_pin=EPD_RST_PIN;epd->dc_pin=EPD_DC_PIN;epd->cs_pin=EPD_CS_PIN;epd->busy_pin=EPD_BUSY_PIN;epd->pwr_pin=EPD_PWR_PIN;if(epd_setup_default_hal(epd)!=EPD_OK)return EPD_ERROR;epd_reset(epd);epd_wait_busy(epd);epd_send_command(epd,0x12);epd_wait_busy(epd);epd_send_command(epd,0x01);epd_send_data(epd,39);epd_send_data(epd,1);epd_send_data(epd,0x00);epd_send_command(epd,0x11);epd_send_data(epd,0x03);epd_send_command(epd,0x44);epd_send_data(epd,0x00);epd_send_data(epd,18);epd_send_command(epd,0x45);epd_send_data(epd,0x00);epd_send_data(epd,0x00);epd_send_data(epd,39);epd_send_data(epd,1);epd_send_command(epd,0x3C);epd_send_data(epd,0x05);epd_send_command(epd,0x18);epd_send_data(epd,0x80);epd_send_command(epd,0x4E);epd_send_data(epd,0x00);epd_send_command(epd,0x4F);epd_send_data(epd,0x00);epd_send_data(epd,0x00);epd_wait_busy(epd);return EPD_OK;}
void EPD_epd2in66g_Clear(EPD *epd, uint8_t clr){if(!epd)return;int sz=epd_linewidth(152)*296;uint8_t*b=(uint8_t*)malloc(sz);if(!b)return;memset(b,clr,sz);epd_send_command(epd,0x24);epd_send_data_buf(epd,b,sz);free(b);epd_send_command(epd,0x22);epd_send_data(epd,0xC7);epd_send_command(epd,0x20);epd_wait_busy(epd);}
void EPD_epd2in66g_Display(EPD *epd, const uint8_t *img){if(!epd||!img)return;epd_send_command(epd,0x24);epd_send_data_buf(epd,img,epd_linewidth(152)*296);epd_send_command(epd,0x22);epd_send_data(epd,0xC7);epd_send_command(epd,0x20);epd_wait_busy(epd);}
void EPD_epd2in66g_Sleep(EPD *epd){if(!epd)return;epd_send_command(epd,0x10);epd_send_data(epd,0x01);epd->delay_ms(2000);epd_teardown_default_hal(epd);}
